Script:
$ErrorActionPreference = 'SilentlyContinue'
$findings = [System.Collections.Generic.List[PSCustomObject]]::new()
$daysBack = if ($Param1) { [int]$Param1 } else { 30 }

# -- Check 1: Core WU Services --
$services = @(
    @{ Name = 'wuauserv'; Display = 'Windows Update' },
    @{ Name = 'BITS';     Display = 'Background Intelligent Transfer (BITS)' },
    @{ Name = 'CryptSvc'; Display = 'Cryptographic Services' },
    @{ Name = 'UsoSvc';   Display = 'Update Orchestrator' }
)
foreach ($svc in $services) {
    $s = Get-Service -Name $svc.Name -ErrorAction SilentlyContinue
    if ($null -eq $s) {
        $findings.Add([PSCustomObject]@{
            Check  = "$($svc.Display) ($($svc.Name))"
            Status = 'ISSUE'
            Detail = 'Service not found. This component may not be installed.'
        })
    } elseif ($s.Status -eq 'Running') {
        $findings.Add([PSCustomObject]@{
            Check  = "$($svc.Display) ($($svc.Name))"
            Status = 'OK'
            Detail = "Running, start type: $($s.StartType). Operational."
        })
    } elseif ($s.StartType -eq 'Disabled') {
        $findings.Add([PSCustomObject]@{
            Check  = "$($svc.Display) ($($svc.Name))"
            Status = 'ISSUE'
            Detail = "Disabled. Updates cannot function without this service. Run WU009 WUServiceReset."
        })
    } elseif ($s.StartType -match 'Auto') {
        $findings.Add([PSCustomObject]@{
            Check  = "$($svc.Display) ($($svc.Name))"
            Status = 'ISSUE'
            Detail = "Stopped but start type is $($s.StartType) -- should be running. Run WU009 WUServiceReset."
        })
    } else {
        $findings.Add([PSCustomObject]@{
            Check  = "$($svc.Display) ($($svc.Name))"
            Status = 'OK'
            Detail = "Stopped, start type: $($s.StartType). This is expected -- service starts on demand when updates are needed."
        })
    }
}

# -- Check 2: System Drive Free Space --
$sysDrive = $env:SystemDrive
$disk = Get-CimInstance -ClassName Win32_LogicalDisk -Filter "DeviceID='$sysDrive'"
if ($null -ne $disk) {
    $freeGB = [math]::Round($disk.FreeSpace / 1GB, 1)
    $totalGB = [math]::Round($disk.Size / 1GB, 0)
    if ($freeGB -lt 5) {
        $findings.Add([PSCustomObject]@{
            Check  = "Disk Space ($sysDrive)"
            Status = 'ISSUE'
            Detail = "CRITICAL: Only $freeGB GB free of $totalGB GB. Even monthly cumulative updates may fail below 5 GB."
        })
    } elseif ($freeGB -lt 20) {
        $findings.Add([PSCustomObject]@{
            Check  = "Disk Space ($sysDrive)"
            Status = 'WARN'
            Detail = "$freeGB GB free of $totalGB GB. Feature updates need at least 20 GB. Monthly patches should still work."
        })
    } else {
        $findings.Add([PSCustomObject]@{
            Check  = "Disk Space ($sysDrive)"
            Status = 'OK'
            Detail = "$freeGB GB free of $totalGB GB. Sufficient for all update types."
        })
    }
} else {
    $findings.Add([PSCustomObject]@{
        Check  = 'Disk Space'
        Status = 'ERROR'
        Detail = "Could not query system drive $sysDrive."
    })
}

# -- Check 3: Pending Reboot --
$rebootReasons = [System.Collections.Generic.List[string]]::new()
if (Test-Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\WindowsUpdate\Auto Update\RebootRequired') {
    $rebootReasons.Add('Windows Update has staged updates waiting for reboot')
}
if (Test-Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Component Based Servicing\RebootPending') {
    $rebootReasons.Add('Component servicing (CBS) requires reboot to finalize')
}
$pfro = (Get-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager' -Name 'PendingFileRenameOperations' -ErrorAction SilentlyContinue).PendingFileRenameOperations
if ($null -ne $pfro) {
    $nonEmpty = @($pfro | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    if ($nonEmpty.Count -gt 0) {
        $rebootReasons.Add('Session Manager has pending file rename operations')
    }
}
if ($rebootReasons.Count -gt 0) {
    $findings.Add([PSCustomObject]@{
        Check  = 'Pending Reboot'
        Status = 'ISSUE'
        Detail = "Reboot required. New updates will not install until this machine restarts. $($rebootReasons -join '; ')."
    })
} else {
    $findings.Add([PSCustomObject]@{
        Check  = 'Pending Reboot'
        Status = 'OK'
        Detail = 'No reboot pending. Machine is clear to accept new updates.'
    })
}

# -- HRESULT lookup table --
$hresultMap = @{}
$hresultMap['0x80070643'] = 'WinRE partition too small or MSI installer failure. May need manual partition resize.'
$hresultMap['0x800F081F'] = 'Component store missing required files. Run WU005 WUComponentHealth.'
$hresultMap['0x80073712'] = 'Component store corruption detected. Run WU005 WUComponentHealth.'
$hresultMap['0x80244022'] = 'Update server returned HTTP 503 (unavailable). Run WU003 WUNetworkCheck.'
$hresultMap['0x8024401C'] = 'Connection to update server timed out. Run WU003 WUNetworkCheck.'
$hresultMap['0x8024002E'] = 'Windows Update is administratively disabled. Run WU002 WUPolicyAudit.'
$hresultMap['0x80070005'] = 'Access denied. Likely third-party AV or Tamper Protection blocking updates.'
$hresultMap['0x80240022'] = 'All updates in batch failed. Examine individual error codes.'
$hresultMap['0x80242014'] = 'Post-reboot finalization still pending. Reboot the machine.'
$hresultMap['0x800F0922'] = 'Safe OS phase failed. Usually WinRE partition or disk space issue.'
$hresultMap['0x80070002'] = 'Required file not found. Component store may need repair. Run WU005.'
$hresultMap['0x80080005'] = 'Server execution failed. Background service may have crashed. Run WU009.'
$hresultMap['0x8007000E'] = 'Out of memory. Close applications and retry.'
$hresultMap['0x80072EE7'] = 'Server name could not be resolved. DNS or network issue. Run WU003.'
$hresultMap['0x80072F8F'] = 'SSL/TLS certificate validation failed. Run WU004 WUTlsCertCheck.'
$hresultMap['0x80096004'] = 'Certificate trust validation failure. Run WU004 WUTlsCertCheck.'
$hresultMap['0x80244019'] = 'WSUS server rejected request (HTTP 503). WSUS may be overloaded.'
$hresultMap['0x800705B4'] = 'Operation timed out. Service may be hung. Run WU009 WUServiceReset.'
$hresultMap['0x80240017'] = 'Update not applicable to this system. Usually not a problem.'
$hresultMap['0x80070BC9'] = 'Reboot required before this update can install. Reboot and retry.'

# -- Check 4 & 6: WU History --
$lastSuccessDate = $null
$failureList = [System.Collections.Generic.List[PSCustomObject]]::new()
$failCount = 0
$successCount = 0
try {
    $session = New-Object -ComObject Microsoft.Update.Session
    $searcher = $session.CreateUpdateSearcher()
    $total = $searcher.GetTotalHistoryCount()
    if ($total -gt 0) {
        $max = if ($total -lt 200) { $total } else { 200 }
        $history = $searcher.QueryHistory(0, $max)
        $cutoff = (Get-Date).AddDays(-$daysBack)
        for ($i = 0; $i -lt $history.Count; $i++) {
            $e = $history.Item($i)
            if ($e.ResultCode -eq 2) {
                if ($null -eq $lastSuccessDate -or $e.Date -gt $lastSuccessDate) {
                    $lastSuccessDate = $e.Date
                }
                if ($e.Date -ge $cutoff) { $successCount++ }
            } elseif ($e.ResultCode -ge 3 -and $e.Date -ge $cutoff) {
                $failCount++
                if ($failureList.Count -lt 5) {
                    $hr = '0x{0:X8}' -f $e.HResult
                    $meaning = $hresultMap[$hr]
                    if ([string]::IsNullOrWhiteSpace($meaning)) {
                        $meaning = "Unknown error. Search $hr on learn.microsoft.com"
                    }
                    $title = if ($e.Title.Length -gt 80) { $e.Title.Substring(0, 77) + '...' } else { $e.Title }
                    $failureList.Add([PSCustomObject]@{
                        Date    = $e.Date.ToString('yyyy-MM-dd')
                        HR      = $hr
                        Title   = $title
                        Meaning = $meaning
                    })
                }
            }
        }
    }
    if ($failCount -gt 0) {
        $findings.Add([PSCustomObject]@{
            Check  = "Update Failures (last $daysBack days)"
            Status = 'ISSUE'
            Detail = "$failCount failed, $successCount succeeded. Top failures:"
        })
        foreach ($fl in $failureList) {
            $findings.Add([PSCustomObject]@{
                Check  = "  $($fl.HR) on $($fl.Date)"
                Status = 'INFO'
                Detail = "$($fl.Title) -- $($fl.Meaning)"
            })
        }
    } else {
        $findings.Add([PSCustomObject]@{
            Check  = "Update History (last $daysBack days)"
            Status = 'OK'
            Detail = "No failed updates. $successCount update(s) succeeded."
        })
    }
} catch {
    $findings.Add([PSCustomObject]@{
        Check  = 'Update History'
        Status = 'ERROR'
        Detail = "Could not query WU history: $($_.Exception.Message)"
    })
}

# -- Check 5: SoftwareDistribution Folder Size --
$sdPath = Join-Path -Path $env:SystemRoot -ChildPath 'SoftwareDistribution'
if (Test-Path -Path $sdPath) {
    try {
        $sdSize = (Get-ChildItem -Path $sdPath -Recurse -File -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum).Sum
        if ($null -eq $sdSize) { $sdSize = 0 }
        if ($sdSize -ge 1073741824) {
            $sdGB = [math]::Round($sdSize / 1GB, 2)
            $findings.Add([PSCustomObject]@{
                Check  = 'SoftwareDistribution Cache'
                Status = 'ISSUE'
                Detail = "$sdGB GB. Bloated cache suggests stuck or failed downloads. Run WU009 WUServiceReset to clear."
            })
        } else {
            $sdMB = [math]::Round($sdSize / 1MB, 0)
            $findings.Add([PSCustomObject]@{
                Check  = 'SoftwareDistribution Cache'
                Status = 'OK'
                Detail = "$sdMB MB. Cache size is normal."
            })
        }
    } catch {
        $findings.Add([PSCustomObject]@{
            Check  = 'SoftwareDistribution Cache'
            Status = 'ERROR'
            Detail = "Could not measure folder: $($_.Exception.Message)"
        })
    }
} else {
    $findings.Add([PSCustomObject]@{
        Check  = 'SoftwareDistribution Cache'
        Status = 'ISSUE'
        Detail = "Folder not found at $sdPath. This should always exist. Run WU009 WUServiceReset."
    })
}

# -- Check 6: Last Successful Update --
if ($null -ne $lastSuccessDate) {
    $daysSince = [math]::Max(0, [math]::Floor(((Get-Date) - $lastSuccessDate).TotalDays))
    if ($daysSince -gt 60) {
        $findings.Add([PSCustomObject]@{
            Check  = 'Last Successful Update'
            Status = 'ISSUE'
            Detail = "$daysSince days ago ($($lastSuccessDate.ToString('yyyy-MM-dd'))). Machine is significantly behind on patches."
        })
    } elseif ($daysSince -gt 30) {
        $findings.Add([PSCustomObject]@{
            Check  = 'Last Successful Update'
            Status = 'WARN'
            Detail = "$daysSince days ago ($($lastSuccessDate.ToString('yyyy-MM-dd'))). Updates appear to have stalled."
        })
    } else {
        $findings.Add([PSCustomObject]@{
            Check  = 'Last Successful Update'
            Status = 'OK'
            Detail = "$daysSince days ago ($($lastSuccessDate.ToString('yyyy-MM-dd'))). Update cadence looks healthy."
        })
    }
} else {
    $findings.Add([PSCustomObject]@{
        Check  = 'Last Successful Update'
        Status = 'ISSUE'
        Detail = 'No successful updates found in available history. Investigate immediately.'
    })
}

# -- Output --
Write-Output ''
Write-Output '=== Windows Update Quick Health ==='
Write-Output ''
$issueCount = @($findings | Where-Object { $_.Status -eq 'ISSUE' -or $_.Status -eq 'ERROR' }).Count
$warnCount = @($findings | Where-Object { $_.Status -eq 'WARN' }).Count
foreach ($f in $findings) {
    $icon = switch ($f.Status) {
        'OK'    { '[OK]  ' }
        'ISSUE' { '[!!]  ' }
        'WARN'  { '[!]   ' }
        'ERROR' { '[ERR] ' }
        'INFO'  { '[i]   ' }
        default { "[$($f.Status)] " }
    }
    Write-Output "$icon$($f.Check)"
    Write-Output "       $($f.Detail)"
}
Write-Output ''
if ($issueCount -eq 0 -and $warnCount -eq 0) {
    Write-Output 'RESULT: No issues detected. Windows Update appears healthy.'
} elseif ($issueCount -eq 0) {
    Write-Output "RESULT: $warnCount warning(s) found. Review items marked [!] above."
} else {
    Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. Review items marked [!!] and [!] above."
}
Write-Output ''
Write-Output 'NEXT:   If services are stopped      -> run WU009 WUServiceReset'
Write-Output '        If policy issues suspected   -> run WU002 WUPolicyAudit'
Write-Output '        If network-related failures  -> run WU003 WUNetworkCheck'
Write-Output '        For deeper investigation     -> run scripts WU002-WU008 in order'
Write-Output ''

$ErrorActionPreference = 'SilentlyContinue'
Write-Output ''
Write-Output '=== Defender & AV Status Triage ==='
Write-Output ''

$issueCount = 0
$warnCount = 0

# State tracking for signal gap analysis
$hasThirdPartyAV = $false
$thirdPartyAVOn = $false
$defenderPassive = $false
$secCenterAvailable = $true

# --- Check 1: Security Center AV Products ---
try {
    $avProducts = Get-CimInstance -Namespace root/SecurityCenter2 -ClassName AntiVirusProduct -ErrorAction Stop
    if ($null -eq $avProducts -or @($avProducts).Count -eq 0) {
        Write-Output '[!!]  Security Center AV Products'
        Write-Output '       No antivirus products registered in Security Center. Machine may be unprotected.'
        $issueCount++
    } else {
        foreach ($av in @($avProducts)) {
            $pState = [UInt32]$av.productState
            $engineBits = $pState -band 0xF000
            $sigBits    = $pState -band 0x00F0
            $ownerBits  = $pState -band 0x0F00

            $engineState = switch ($engineBits) {
                0x1000 { 'On' }
                0x0000 { 'Off' }
                0x2000 { 'Snoozed' }
                0x3000 { 'Expired' }
                default { "Unknown (0x$($engineBits.ToString('X4')))" }
            }

            $sigState = if ($sigBits -eq 0x0000) { 'Current' } else { 'Outdated' }
            $owner    = if ($ownerBits -eq 0x0100) { 'Microsoft' } else { 'Third-party' }

            $isDefender = ($av.displayName -like '*Windows Defender*' -or $av.displayName -like '*Microsoft Defender*')

            if (-not $isDefender) {
                $hasThirdPartyAV = $true
                if ($engineState -eq 'On') { $thirdPartyAVOn = $true }
            }

            # Ghost detection: verify executable exists on disk
            $isGhost = $false
            $exePath = $av.pathToSignedReportingExe
            if (-not [string]::IsNullOrWhiteSpace($exePath)) {
                # Skip URI-style paths (windowsdefender://) and environment variable paths
                if ($exePath -notlike 'windowsdefender://*' -and $exePath -notlike '%*') {
                    if (-not (Test-Path $exePath)) {
                        $isGhost = $true
                    }
                }
            }

            if ($isGhost) {
                Write-Output "[!!]  Security Center: $($av.displayName)"
                Write-Output "       GHOST REGISTRATION -- product registered but executable not found on disk."
                Write-Output "       Path: $exePath"
                Write-Output '       Intune sees this as the AV, but it is not installed. Run DEF003 DEFThirdPartyAV.'
                $issueCount++
            } elseif (-not $isDefender -and ($engineState -ne 'On')) {
                Write-Output "[!!]  Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
                Write-Output '       Registered but not actively protecting. Check third-party AV configuration.'
                $issueCount++
            } elseif (-not $isDefender -and $engineState -eq 'On') {
                Write-Output "[i]   Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
                Write-Output '       Third-party AV is primary. Defender should be in passive mode.'
            } else {
                Write-Output "[OK]  Security Center: $($av.displayName)"
                Write-Output "       State: $engineState, Signatures: $sigState, Origin: $owner."
            }
        }
    }
} catch {
    $secCenterAvailable = $false
    Write-Output '[i]   Security Center AV Products'
    Write-Output '       SecurityCenter2 namespace not available (normal on Windows Server).'
    Write-Output '       Skipping Security Center checks. Defender status checked below.'
}

# --- Check 2: Defender Status (Get-MpComputerStatus) ---
$mpOK = $false
try {
    $mpStatus = Get-MpComputerStatus -ErrorAction Stop
    $mpOK = $true

    $runMode = $mpStatus.AMRunningMode
    $rtpEnabled = $mpStatus.RealTimeProtectionEnabled

    # Running mode verdict
    if ($runMode -eq 'Normal' -and $rtpEnabled) {
        Write-Output '[OK]  Defender Running Mode'
        Write-Output "       Mode: $runMode. Real-time protection: Enabled. Defender is active and protecting."
    } elseif ($runMode -like '*Passive*') {
        $defenderPassive = $true
        if ($hasThirdPartyAV) {
            Write-Output '[i]   Defender Running Mode'
            Write-Output "       Mode: $runMode. This is expected -- a third-party AV is primary."
        } else {
            Write-Output '[!!]  Defender Running Mode'
            Write-Output "       Mode: $runMode but no third-party AV detected in Security Center."
            Write-Output '       A ghost AV registration may be forcing passive mode. Machine may be unprotected.'
            Write-Output '       Run DEF003 DEFThirdPartyAV to investigate.'
            $issueCount++
        }
    } elseif ($runMode -eq 'EDR Block Mode') {
        Write-Output '[i]   Defender Running Mode'
        Write-Output "       Mode: EDR Block Mode. AV is passive but EDR detections are actively blocked."
    } elseif ($runMode -eq 'Normal' -and -not $rtpEnabled) {
        Write-Output '[!!]  Defender Running Mode'
        Write-Output "       Mode: $runMode but Real-time protection is DISABLED."
        Write-Output '       Defender is primary but not scanning files. Run DEF004 DEFRealtimeProtection.'
        $issueCount++
    } else {
        $rtpText = if ($rtpEnabled) { 'Enabled' } else { 'Disabled' }
        Write-Output '[i]   Defender Running Mode'
        Write-Output "       Mode: $runMode. Real-time protection: $rtpText."
    }

    # Definition age
    $sigAge = $mpStatus.AntivirusSignatureAge
    $sigUpdated = $mpStatus.AntivirusSignatureLastUpdated
    $sigDateStr = 'unknown'
    if ($null -ne $sigUpdated -and $sigUpdated -ne [datetime]::MinValue) {
        $sigDateStr = $sigUpdated.ToString('yyyy-MM-dd HH:mm')
    }

    if ($sigAge -gt 3) {
        Write-Output '[!!]  Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Definitions are stale."
        Write-Output '       Run DEF002 DEFDefinitionHealth to diagnose update failures.'
        $issueCount++
    } elseif ($sigAge -gt 1) {
        Write-Output '[!]   Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Slightly behind."
        $warnCount++
    } else {
        Write-Output '[OK]  Definition Age'
        Write-Output "       $sigAge day(s) old (last updated: $sigDateStr). Definitions are current."
    }

    # Scan ages (only if Defender is active, not passive)
    if (-not $defenderPassive) {
        $quickAge = $mpStatus.QuickScanAge
        $fullAge  = $mpStatus.FullScanAge

        if ($fullAge -gt 30) {
            Write-Output '[!]   Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago. No full scan in over 30 days."
            $warnCount++
        } elseif ($quickAge -gt 14) {
            Write-Output '[!]   Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago. No quick scan in over 14 days."
            $warnCount++
        } else {
            Write-Output '[OK]  Scan History'
            Write-Output "       Quick scan: $quickAge day(s) ago. Full scan: $fullAge day(s) ago."
        }
    }

    # Platform info (informational)
    Write-Output '[i]   Platform Info'
    Write-Output "       Product: $($mpStatus.AMProductVersion), Engine: $($mpStatus.AMEngineVersion), NIS Engine: $($mpStatus.NISEngineVersion)."

    # Tamper protection (informational)
    $tamper = $mpStatus.IsTamperProtected
    if ($tamper) {
        Write-Output '[i]   Tamper Protection'
        Write-Output '       Enabled. Defender settings are protected from unauthorized changes.'
    } else {
        Write-Output '[i]   Tamper Protection'
        Write-Output '       Disabled. Defender settings can be modified by local admin or malware.'
    }

} catch {
    Write-Output '[!!]  Defender Status'
    Write-Output "       Get-MpComputerStatus failed: $($_.Exception.Message)"
    Write-Output '       Defender module may not be installed or is in a broken state.'
    $issueCount++
}

# --- Check 3: Core Defender Services ---
$services = @(
    @{ Name = 'WinDefend'; Display = 'Windows Defender Antivirus (WinDefend)'; ExpectedStart = 'Automatic' },
    @{ Name = 'WdNisSvc';  Display = 'Network Inspection Service (WdNisSvc)';  ExpectedStart = 'Manual' }
)

foreach ($svc in $services) {
    $s = Get-Service -Name $svc.Name -ErrorAction SilentlyContinue
    if ($null -eq $s) {
        Write-Output "[!!]  $($svc.Display)"
        Write-Output '       Service not found. Defender may not be installed.'
        $issueCount++
    } else {
        $startType = $s.StartType.ToString()
        $status    = $s.Status.ToString()

        if ($startType -eq 'Disabled') {
            Write-Output "[!!]  $($svc.Display)"
            Write-Output "       DISABLED. Service cannot start. Run DEF008 DEFRemediation."
            $issueCount++
        } elseif ($status -ne 'Running' -and $svc.ExpectedStart -eq 'Automatic') {
            Write-Output "[!!]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. Should be running. Run DEF008 DEFRemediation."
            $issueCount++
        } elseif ($status -ne 'Running' -and $svc.ExpectedStart -eq 'Manual') {
            Write-Output "[OK]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. This is expected -- service starts on demand."
        } else {
            Write-Output "[OK]  $($svc.Display)"
            Write-Output "       $status, start type: $startType. Operational."
        }
    }
}

# --- Check 4: Defender for Endpoint (MDE Sensor) ---
$sense = Get-Service -Name 'Sense' -ErrorAction SilentlyContinue
if ($null -eq $sense) {
    Write-Output '[i]   Defender for Endpoint (Sense)'
    Write-Output '       Sense service not found. Device is not onboarded to MDE (may be expected).'
} else {
    $senseStatus = $sense.Status.ToString()
    $senseStart  = $sense.StartType.ToString()

    if ($senseStart -eq 'Disabled') {
        Write-Output '[!!]  Defender for Endpoint (Sense)'
        Write-Output "       DISABLED. MDE sensor cannot start. Onboard the device or check policies."
        $issueCount++
    } elseif ($senseStatus -ne 'Running') {
        Write-Output '[!!]  Defender for Endpoint (Sense)'
        Write-Output "       $senseStatus, start type: $senseStart. MDE sensor is not running."
        $issueCount++
    } else {
        $onboardReg = Get-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows Advanced Threat Protection\Status' -ErrorAction SilentlyContinue
        if ($null -ne $onboardReg -and $onboardReg.OnboardingState -eq 1) {
            $orgId = $onboardReg.OrgId
            Write-Output '[OK]  Defender for Endpoint (Sense)'
            Write-Output "       Running, onboarded. OrgId: $orgId."
        } else {
            Write-Output '[!]   Defender for Endpoint (Sense)'
            Write-Output "       Running but onboarding state unclear. Check MDE portal."
            $warnCount++
        }
    }
}

# --- Check 5: Signal Gap Analysis ---
if ($secCenterAvailable -and $mpOK) {
    if ($defenderPassive -and -not $hasThirdPartyAV) {
        Write-Output '[!!]  Signal Gap Analysis'
        Write-Output '       CRITICAL: Defender is in passive mode but no third-party AV is registered.'
        Write-Output '       A ghost AV registration may be the cause. Machine is likely UNPROTECTED.'
        Write-Output '       Run DEF003 DEFThirdPartyAV to investigate and DEF008 to remediate.'
    } elseif (-not $defenderPassive -and $thirdPartyAVOn) {
        Write-Output '[!!]  Signal Gap Analysis'
        Write-Output '       Defender is in active mode while a third-party AV is also active.'
        Write-Output '       Two AV engines running simultaneously causes severe performance issues.'
        Write-Output '       Run DEF003 DEFThirdPartyAV to resolve the conflict.'
        $issueCount++
    } else {
        Write-Output '[OK]  Signal Gap Analysis'
        Write-Output '       Security Center and Defender ground truth are consistent.'
    }
} else {
    Write-Output '[i]   Signal Gap Analysis'
    Write-Output '       Skipped -- Security Center or Defender status was not available for cross-reference.'
}

# --- Summary ---
Write-Output ''
$totalProblems = $issueCount + $warnCount
if ($totalProblems -eq 0) {
    Write-Output 'RESULT: No issues detected. Defender appears healthy.'
} elseif ($issueCount -gt 0 -and $warnCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) and $warnCount warning(s) found. Review items marked [!!] and [!] above."
} elseif ($issueCount -gt 0) {
    Write-Output "RESULT: $issueCount issue(s) found. Review items marked [!!] above."
} else {
    Write-Output "RESULT: $warnCount warning(s) found. Review items marked [!] above."
}
Write-Output ''
